VALUES
  ('locality-d0d1b9a2-moex-00564', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '稅捐機關依規定開徵遺產稅10萬元，惟納稅義務人無力以現金繳納，改以股票抵繳；稅捐機關伺 機於市場處分變現11萬元並繳庫，依中央政府普通公務單位會計制度之一致規定，稅捐機關取得 股票抵繳遺產稅時應為之會計分錄為何？', '["借：抵繳收入實物11萬元，貸：稅課收入10萬元、其他收入1萬元", "借：抵繳收入實物10萬元，貸：稅課收入10萬元", "借：抵繳收入實物11萬元，貸：稅課收入11萬元", "借：抵繳收入實物11萬元，貸：稅課收入10萬元、遞延收入10萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00565', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '甲機關X9年度之全年度歲出預算$1,000,000，因應新冠肺炎（COVID-19），增購紅外線熱像儀系 統一批$500,000於X9年7月間分別奉准動支第一預備金$100,000及第二預備金$400,000支應， 請依中央政府普通公務單位會計制度之一致規定，計算上開預備金奉准動支時，結帳前全年度「預 計撥入數」科目總額應為何？', '["$1,500,000", "$1,400,000", "$1,100,000", "$1,000,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
